INSERT INTO `admin_contents` (`page_key`, `page_title`, `content`, `updated_at`, `is_hidden`) VALUES
('about/business-area', '사업영역', '완제의약품 R&D 및 마케팅, 글로벌 원료의약품(API) 공급, 그리고 약물방출조절(DDS) 기반 고품격 위탁생산개발(CDMO) 서비스를 바탕으로 세계인의 삶의 질을 높입니다.
