INSERT INTO `news` (`id`, `category`, `title`, `content`, `views`, `file_url`, `file_name`, `created_at`) VALUES
(1, 'press', '다산제약, 신규 R&D 연구센터 개소로 혁신 신약 파이프라인 가속화', '다산제약이 최첨단 신약 연구센터를 공식 오픈하고 차세대 의약품 파이프라인 개발에 속도를 냅니다. 연구소 소개 및 인터뷰 내용 포함...', 124, NULL, NULL, '2026-06-18 05:11:31'),
(2, 'press', '다산제약, 글로벌 제약사와 CDMO 협력 양해각서(MOU) 체결', '본 협약을 통해 고난도 고형제 및 개량신약 위탁개발생산(CDMO) 사업 영역을 글로벌 시장으로 본격 확장할 예정입니다.', 98, NULL, NULL, '2026-06-18 05:11:31'),
(3, 'ir', '2026년 제1분기 재무 성과 요약 및 IR 공시 안내', '1분기 매출 증가율 및 연구개발 투자 비율 등 핵심 재무 실적이 공시 정보에 반영되었습니다.', 56, NULL, NULL, '2026-06-18 05:11:31'),
(4, 'ir', '2026년도 정기 주주총회 소집 공고', '정기 주주총회 소집 장소 및 의결 사항 등 상세 정보 안내문입니다.', 74, NULL, NULL, '2026-06-18 05:11:31'),
(5, 'press', '다산제약, ESG 인증 확보…IPO 앞두고 신뢰 다진다', '<ol><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span><span style="color: rgb(97, 97, 97); background-color: rgb(255, 255, 255);">2026년 시무식서 ESG 경영시스템 인증 수여</span></li><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span><span style="color: rgb(97, 97, 97); background-color: rgb(255, 255, 255);">2025년 매출 1000억 돌파 이어 올해 1400억 목표</span></li><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span><span style="color: rgb(97, 97, 97); background-color: rgb(255, 255, 255);">30년 DDS 기술력 바탕 글로벌 시장 공략 포부</span></li></ol><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">[데일리팜] </span><a href="https://www.dailypharm.com/user/news/334466?REFERER=NP" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.dailypharm.com/user/news/334466?REFERER=NP</a></p><p><br></p>', 0, NULL, NULL, '2026-06-24 00:21:45'),
(6, 'press', '다산제약, 창립 30주년 맞는 2026년 시무식 통해 실행 과제 발표', '<h1><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">다산제약, 창립 30주년 맞는 2026년 시무식 통해 실행 과제 발표</span></h1><h2><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">지난해 매출 1,000억 달성 기반 AI·효율 중심 경영 고도화‥책임경영 및 거버넌스 강화 추진</span></h2><h2><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">류형선 대표, "지난 30년 축적 위에 더 높은 기준과 실행으로 다음 30년의 성장 기반 만들 것"</span></h2><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);"> </span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);"> </span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">&lt;제약지&gt;</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">메디파나 </span><a href="https://www.medipana.com/news/articleView.html?idxno=404904" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.medipana.com/news/articleView.html?idxno=404904</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">메디소비자 </span><a href="https://www.medisobizanews.com/news/articleView.html?idxno=132991" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.medisobizanews.com/news/articleView.html?idxno=132991</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">약업 신문 </span><a href="https://www.yakup.com/news/index.html?mode=view&amp;cat=12&amp;nid=321417" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.yakup.com/news/index.html?mode=view&amp;cat=12&amp;nid=321417</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">메디칼타임즈 </span><a href="https://www.medicaltimes.com/Main/News/NewsView.html?ID=1166710&amp;ref=naverpc" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.medicaltimes.com/Main/News/NewsView.html?ID=1166710&amp;ref=naverpc</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);"> </span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">&lt;경제지&gt;</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">머니S </span><a href="https://www.moneys.co.kr/article/2026010513193569512" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.moneys.co.kr/article/2026010513193569512</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">프레스나인 </span><a href="https://www.press9.kr/news/articleView.html?idxno=70521" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.press9.kr/news/articleView.html?idxno=70521</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">뉴스핌 </span><a href="https://www.newspim.com/news/view/20260105000646" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.newspim.com/news/view/20260105000646</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">글로벌경제 </span><a href="https://www.getnews.co.kr/news/articleView.html?idxno=855965" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.getnews.co.kr/news/articleView.html?idxno=855965</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">서울경제 </span><a href="https://www.sentv.co.kr/article/view/sentv202601050065" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.sentv.co.kr/article/view/sentv202601050065</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">뉴스웨이 </span><a href="https://www.newsway.co.kr/news/view?ud=2026010514312422125" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.newsway.co.kr/news/view?ud=2026010514312422125</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">서울와이어 </span><a href="https://www.seoulwire.com/news/articleView.html?idxno=700058" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.seoulwire.com/news/articleView.html?idxno=700058</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">FETV </span><a href="https://www.fetv.co.kr/news/article.html?no=209203" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.fetv.co.kr/news/article.html?no=209203</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">포인트데일리 </span><a href="https://www.pointdaily.co.kr/news/articleView.html?idxno=287453" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.pointdaily.co.kr/news/articleView.html?idxno=287453</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);"> </span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">&lt;일반&gt;</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">메트로 </span><a href="https://www.metroseoul.co.kr/article/20260105500297" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://www.metroseoul.co.kr/article/20260105500297</a></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">더팩트 </span><a href="https://news.tf.co.kr/read/economy/2279047.htm" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(85, 85, 85);">https://news.tf.co.kr/read/economy/2279047.htm</a></p><p><br></p>', 0, NULL, NULL, '2026-06-24 00:22:06');
